fn find(x: usize, parent: &mut [i32]) -> usize {
    if parent[x] < 0 {
        return x;
    }
    let root = find(parent[x] as usize, parent);
    parent[x] = root as i32;
    root
}

fn unite(x: usize, y: usize, parent: &mut [i32]) -> bool {
    let mut x = find(x, parent);
    let mut y = find(y, parent);
    if x == y {
        return false;
    }
    if parent[x] > parent[y] {
        std::mem::swap(&mut x, &mut y);
    }
    parent[x] += parent[y];
    parent[y] = x as i32;
    true
}

fn update(mut i: usize, x: i64, seg: &mut [i64], size: usize) {
    i += size;
    seg[i] = x;
